    private lateinit var ttsManager: TTSManager
    private var screenReceiverRegistered = false
    private val phraseRepository by lazy {
        SharedPreferencesPhraseRepository(applicationContext)
    }
    private val viewModel: AACViewModel by viewModels {
        AACViewModelFactory(phraseRepository)
    }

    private val screenReceiver = object : BroadcastReceiver() {
        override fun onReceive(context: Context, intent: Intent) {
            if (intent.action == Intent.ACTION_SCREEN_OFF) {
                NotificationHelper.recreateSilentLockScreenNotification(context)
            }
        }
    }

    @OptIn(ExperimentalMaterial3WindowSizeClassApi::class)
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge() // 开启边到边显示

        startService(Intent(this, TaskRemovedCleanupService::class.java))
        registerScreenReceiver()
        WindowConfig.setup(this) // 配置锁屏窗口权限

        ttsManager = TTSManager(this)

        setContent {
            val windowSizeClass = calculateWindowSizeClass(this)
            KigHelperTheme {
                PermissionHandler() // 检查必要权限（通知、悬浮窗）
                UpdateHandler() // 处理版本更新提示

                KigHelperApp(
                    windowSize = windowSizeClass,
                    viewModel = viewModel,
                    onSpeak = { text -> ttsManager.speak(text) },
                    onStop = { ttsManager.stop() },
                    onPhraseSpoken = { phrase ->
                        // 当短语被使用时更新通知
                        // 传递 label 用于显示，speech 用于 TTS 播放
                        NotificationHelper.showSilentLockScreenNotification(
                            this@MainActivity,
                            phraseLabel = phrase.label,
                            phraseSpeech = phrase.speech
                        )
                    }
                )
            }
        }

        // 加载最后使用的短语并显示在通知中
        loadLastUsedPhraseForNotification()
    }

    private fun loadLastUsedPhraseForNotification() {
        lifecycleScope.launch {
            viewModel.getLastUsedPhrase()?.let { phrase ->
                // 如果有最后使用的短语，用它初始化通知
                NotificationHelper.showSilentLockScreenNotification(
                    this@MainActivity,
                    phraseLabel = phrase.label,
                    phraseSpeech = phrase.speech
                )
            }
        }
    }

    override fun onStart() {
        super.onStart()
        NotificationHelper.cancelNotification(this)
    }

    override fun onStop() {
        super.onStop()
        NotificationHelper.showSilentLockScreenNotification(this)
    }

    override fun onDestroy() {
        NotificationHelper.cancelNotification(this)
        stopService(Intent(this, TaskRemovedCleanupService::class.java))
        if (screenReceiverRegistered) {
            unregisterReceiver(screenReceiver)
            screenReceiverRegistered = false
        }
        ttsManager.shutDown()
        super.onDestroy()
    }

    private fun registerScreenReceiver() {
        ContextCompat.registerReceiver(
            this,
            screenReceiver,
            IntentFilter(Intent.ACTION_SCREEN_OFF),
            ContextCompat.RECEIVER_NOT_EXPORTED
        )
        screenReceiverRegistered = true
    }
}

package com.ziegler.kighelper.utils

import android.annotation.SuppressLint
import android.app.Notification
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.PendingIntent
import android.content.Context
import android.content.Intent
import android.os.Build
import androidx.core.app.NotificationCompat
import com.ziegler.kighelper.MainActivity
import com.ziegler.kighelper.R

/**
 * 锁屏快捷通知工具 - 支持 Live Updates
 * 负责创建静默通知，让用户在后台或锁屏时快速回到主界面。
 * 通知会显示在通知中心的 Live Updates 区域。
 */
object NotificationHelper {
    private const val CHANNEL_ID = "aac_silent_channel"
    private const val NOTIFICATION_ID = 888

    @SuppressLint("FullScreenIntentPolicy", "MissingPermission")
    fun showSilentLockScreenNotification(context: Context) {
        val appContext = context.applicationContext
        val notificationManager = appContext.notificationManager()

        notificationManager.createNotificationChannel(createNotificationChannel())

        val notification = buildNotification(appContext, createLaunchPendingIntent(appContext))

        // 验证 Live Updates 支持 (仅用于调试 - 需要 API 36+)
        if (Build.VERSION.SDK_INT >= 36) {
            val canPost = notificationManager.canPostPromotedNotifications()
            val hasCharacteristics = notification.hasPromotableCharacteristics()
            android.util.Log.d("NotificationHelper",
                "Live Updates - canPost: $canPost, hasPromotableCharacteristics: $hasCharacteristics")
        }

        notificationManager.notify(NOTIFICATION_ID, notification)
    }

    fun recreateSilentLockScreenNotification(context: Context) {
        cancelNotification(context)
        showSilentLockScreenNotification(context)
    }

    fun cancelNotification(context: Context) {
        context.applicationContext.notificationManager().cancel(NOTIFICATION_ID)
    }

    /**
     * 检查应用是否可以发送 Live Update 通知
     * @return true 如果用户在设置中启用了 Live Updates (需要 API 36+)
     */
    @Suppress("NewApi")
    fun canPostLiveUpdates(context: Context): Boolean {
        if (Build.VERSION.SDK_INT >= 36) {
            val notificationManager = context.applicationContext.notificationManager()
            return notificationManager.canPostPromotedNotifications()
        }
        return false
    }

    /**
     * 打开系统设置，允许用户管理 Live Updates 权限 (需要 API 36+)
     */
    fun openLiveUpdatesSettings(context: Context) {
        if (Build.VERSION.SDK_INT >= 36) {
            try {
                val intent = Intent("android.settings.MANAGE_APP_PROMOTED_NOTIFICATIONS")
                intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                context.startActivity(intent)
            } catch (e: Exception) {
                android.util.Log.e("NotificationHelper", "无法打开 Live Updates 设置", e)
            }
        }
    }

    private fun createNotificationChannel(): NotificationChannel {
        return NotificationChannel(
            CHANNEL_ID,
            "后台辅助模式",
            NotificationManager.IMPORTANCE_HIGH
        ).apply {
            description = "应用在后台时常驻通知，便于快速返回"
            setSound(null, null)
            enableVibration(false)
            enableLights(false)
            lockscreenVisibility = NotificationCompat.VISIBILITY_PUBLIC
        }
    }

    private fun createLaunchPendingIntent(context: Context): PendingIntent {
        val intent = Intent(context, MainActivity::class.java).apply {
            // 复用已有主界面，避免通知点击后重复创建 Activity
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_SINGLE_TOP
        }

        return PendingIntent.getActivity(
            context,
            0,
            intent,
            PendingIntent.FLAG_IMMUTABLE or PendingIntent.FLAG_UPDATE_CURRENT
        )
    }

    @SuppressLint("FullScreenIntentPolicy")
    private fun buildNotification(
        context: Context,
        pendingIntent: PendingIntent,
        phraseText: String? = null
    ): Notification {
        val title = phraseText ?: "KigHelper 正在后台运行"
        val chipText = phraseText ?: "待机中"

        return NotificationCompat.Builder(context, CHANNEL_ID)
            .setSmallIcon(R.drawable.ic_speaker)  // 使用音频图标
            .setContentTitle(title)  // 显示短语作为标题
            .setContentText("点击返回主界面")  // 保持固定的内容文本
            .setPriority(NotificationCompat.PRIORITY_MAX)
            .setCategory(NotificationCompat.CATEGORY_SERVICE)  // 使用 SERVICE 类别以符合 Live Updates 要求
            .setVisibility(NotificationCompat.VISIBILITY_PUBLIC)
            .setContentIntent(pendingIntent)
            .setFullScreenIntent(pendingIntent, true)
            .setSilent(true)
            .setOngoing(true)  // 必需：设置为持续通知
            .setAutoCancel(false)
            .setWhen(System.currentTimeMillis())  // 设置时间戳用于状态芯片显示
            .setShowWhen(false)  // 不显示时间，使用自定义芯片文本
            .apply {
                // 添加 Live Updates 支持 - 让通知显示在 Live Updates 区域
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.UPSIDE_DOWN_CAKE) {
                    setRequestPromotedOngoing(true)  // 必需：请求提升为 Live Update
                    // 设置状态芯片的关键文本（显示短语）
                    setShortCriticalText(chipText)
                }
            }
            .build()
    }

    private fun Context.notificationManager(): NotificationManager {
        return getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
    }
}

package com.ziegler.kighelper.utils

import android.annotation.SuppressLint
import android.app.Notification
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.PendingIntent
import android.content.Context
import android.content.Intent
import android.os.Build
import androidx.core.app.NotificationCompat
import com.ziegler.kighelper.MainActivity
import com.ziegler.kighelper.R

/**
 * 锁屏快捷通知工具 - 支持 Live Updates
 * 负责创建静默通知，让用户在后台或锁屏时快速回到主界面。
 * 通知会显示在通知中心的 Live Updates 区域。
 */
object NotificationHelper {
    private const val CHANNEL_ID = "aac_silent_channel"
    private const val NOTIFICATION_ID = 888

    // 存储当前的短语文本，用于更新通知
    private var currentPhraseText: String? = null

    @SuppressLint("FullScreenIntentPolicy", "MissingPermission")
    fun showSilentLockScreenNotification(context: Context, phraseText: String? = null) {
        val appContext = context.applicationContext
        val notificationManager = appContext.notificationManager()

        notificationManager.createNotificationChannel(createNotificationChannel())

        // 更新当前短语文本
        if (phraseText != null) {
            currentPhraseText = phraseText
        }

        val notification = buildNotification(appContext, createLaunchPendingIntent(appContext), currentPhraseText)

        // 验证 Live Updates 支持 (仅用于调试 - 需要 API 36+)
        if (Build.VERSION.SDK_INT >= 36) {
            val canPost = notificationManager.canPostPromotedNotifications()
            val hasCharacteristics = notification.hasPromotableCharacteristics()
            android.util.Log.d("NotificationHelper",
                "Live Updates - canPost: $canPost, hasPromotableCharacteristics: $hasCharacteristics")
        }

        notificationManager.notify(NOTIFICATION_ID, notification)
    }

    fun recreateSilentLockScreenNotification(context: Context) {
        cancelNotification(context)
        showSilentLockScreenNotification(context, currentPhraseText)
    }

    fun cancelNotification(context: Context) {
        context.applicationContext.notificationManager().cancel(NOTIFICATION_ID)
    }

    /**
     * 检查应用是否可以发送 Live Update 通知
     * @return true 如果用户在设置中启用了 Live Updates (需要 API 36+)
     */
    @Suppress("NewApi")
    fun canPostLiveUpdates(context: Context): Boolean {
        if (Build.VERSION.SDK_INT >= 36) {
            val notificationManager = context.applicationContext.notificationManager()
            return notificationManager.canPostPromotedNotifications()
        }
        return false
    }

    /**
     * 打开系统设置，允许用户管理 Live Updates 权限 (需要 API 36+)
     */
    fun openLiveUpdatesSettings(context: Context) {
        if (Build.VERSION.SDK_INT >= 36) {
            try {
                val intent = Intent("android.settings.MANAGE_APP_PROMOTED_NOTIFICATIONS")
                intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                context.startActivity(intent)
            } catch (e: Exception) {
                android.util.Log.e("NotificationHelper", "无法打开 Live Updates 设置", e)
            }
        }
    }

    private fun createNotificationChannel(): NotificationChannel {
        return NotificationChannel(
            CHANNEL_ID,
            "后台辅助模式",
            NotificationManager.IMPORTANCE_HIGH
        ).apply {
            description = "应用在后台时常驻通知，便于快速返回"
            setSound(null, null)
            enableVibration(false)
            enableLights(false)
            lockscreenVisibility = NotificationCompat.VISIBILITY_PUBLIC
        }
    }

    private fun createLaunchPendingIntent(context: Context): PendingIntent {
        val intent = Intent(context, MainActivity::class.java).apply {
            // 复用已有主界面，避免通知点击后重复创建 Activity
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_SINGLE_TOP
        }

        return PendingIntent.getActivity(
            context,
            0,
            intent,
            PendingIntent.FLAG_IMMUTABLE or PendingIntent.FLAG_UPDATE_CURRENT
        )
    }

    @SuppressLint("FullScreenIntentPolicy")
    private fun buildNotification(
        context: Context,
        pendingIntent: PendingIntent,
        phraseText: String? = null
    ): Notification {
        val title = phraseText ?: "KigHelper 正在后台运行"
        val chipText = phraseText ?: "待机中"

        return NotificationCompat.Builder(context, CHANNEL_ID)
            .setSmallIcon(R.drawable.ic_speaker)  // 使用音频图标
            .setContentTitle(title)  // 显示短语作为标题
            .setContentText("点击返回主界面")  // 保持固定的内容文本
            .setPriority(NotificationCompat.PRIORITY_MAX)
            .setCategory(NotificationCompat.CATEGORY_SERVICE)  // 使用 SERVICE 类别以符合 Live Updates 要求
            .setVisibility(NotificationCompat.VISIBILITY_PUBLIC)
            .setContentIntent(pendingIntent)
            .setFullScreenIntent(pendingIntent, true)
            .setSilent(true)
            .setOngoing(true)  // 必需：设置为持续通知
            .setAutoCancel(false)
            .setWhen(System.currentTimeMillis())  // 设置时间戳用于状态芯片显示
            .setShowWhen(false)  // 不显示时间，使用自定义芯片文本
            .apply {
                // 添加 Live Updates 支持 - 让通知显示在 Live Updates 区域
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.UPSIDE_DOWN_CAKE) {
                    setRequestPromotedOngoing(true)  // 必需：请求提升为 Live Update
                    // 设置状态芯片的关键文本（显示短语）
                    setShortCriticalText(chipText)
                }
            }
            .build()
    }

    private fun Context.notificationManager(): NotificationManager {
        return getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
    }
}
